@friendlyName("BillingWorkflowRetrySettings")
model BillingWorkflowRetrySettings {
  @visibility(Lifecycle.Read, Lifecycle.Create, Lifecycle.Update)
  max_attempts?: integer = 3;
  @encode(DurationKnownEncoding.ISO8601) @example("PT5M")
  @visibility(Lifecycle.Read, Lifecycle.Create, Lifecycle.Update)
  initial_delay?: string = "PT1M";
}
// then add to BillingWorkflow:  retry?: BillingWorkflowRetrySettings;

@friendlyName("EnumFieldFilter")
@extension("x-go-type", "filters.FilterEnum")
@extension("x-go-type-import", #{ path: "github.com/openmeterio/openmeter/api/v3/filters" })
union EnumFieldFilter {
  string: string,
  object: {
    eq?: string,
    neq?: string,
    @encode(ArrayEncoding.commaDelimited)
    oeq?: string[],
  },
}
